import{_ as t,c as e,o as r,a2 as a}from"./chunks/framework.Sicmpk4x.js";const u=JSON.parse('{"title":"Preface","description":"","frontmatter":{"aside":false},"headers":[],"relativePath":"book/preface.md","filePath":"book/preface.md"}'),o={name:"book/preface.md"},d=a('<h1 id="preface" tabindex="-1">Preface <a class="header-anchor" href="#preface" aria-label="Permalink to &quot;Preface&quot;">​</a></h1><p>This book contains a series of course projects which help students read all the code of <a href="https://github.com/yhzhang0128/egos-2000" target="_blank"> egos-2000</a>, a teaching operating system. There are 6 <strong>core projects</strong> covering most of the OS concepts for an undergraduate-level OS course (e.g., CS4411 at Cornell).</p><table tabindex="0"><thead><tr><th>Core projects</th><th>OS concepts</th></tr></thead><tbody><tr><td>Hello, World!</td><td>memory, pointer, stack, user-level ISA</td></tr><tr><td>Non-preemptive Multithreading</td><td>context switch, multithreading, synchronization</td></tr><tr><td>Preemptive Scheduling</td><td>timer, interrupt handling, scheduler</td></tr><tr><td>System Call and Memory Protection</td><td>exception handling, control register, privilege level</td></tr><tr><td>Page Table Translation</td><td>RISC-V Sv32 translation</td></tr><tr><td>File System</td><td>disk layout, inode, virtualization</td></tr></tbody></table><p>And there are 3 <strong>advanced projects</strong> covering more OS concepts for a master-level OS course (e.g., CS5411 at Cornell).</p><table tabindex="0"><thead><tr><th>Advanced projects</th><th>OS concepts</th></tr></thead><tbody><tr><td>SD Card Driver</td><td>memory-mapped I/O, bus controller, device driver</td></tr><tr><td>Ethernet and UDP</td><td>data link layer, IP layer, transportation layer</td></tr><tr><td>Multi-core and Atomic Instruction</td><td>atomic instruction, spinlock, critical section</td></tr></tbody></table><p>Now, let&#39;s get hands dirty and have some fun!</p>',6),n=[d];function c(s,i,l,h,p,m){return r(),e("div",null,n)}const f=t(o,[["render",c]]);export{u as __pageData,f as default};
